#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv_limb = 0.5 + (vUv-0.5)*vec2(1.18,1.2) + vec2(0,1)*0.08;
float1 limb = texture(sampler_fc_main, uv_limb).x;

vec2 uv_l = (vUv - 0.5)*vec2(1,-1)*uAspect.xy;
vec2 uv_r = uv_l;
vec2 uv_ll = uv_l + vec2(0.105,-0.015);
vec2 uv_rr = uv_l - vec2(0.105,+0.015);

s = _qb.x;
c = _qb.y;
uv_l = 0.5 + 3.5*vec2( s*uv_l.x + c*uv_l.y, c*uv_l.x - s*uv_l.y)*uAspect.yx + vec2(+0.45,-0.67);

s = _qb.z;
c = _qb.w;
uv_r = 0.5 + 3.5*vec2( s*uv_r.x + c*uv_r.y, c*uv_r.x - s*uv_r.y)*uAspect.yx + vec2(-0.45,-0.67);

s = _qc.x;
c = _qc.y;
uv_ll = 0.5 + 1.8*vec2( s*uv_ll.x + c*uv_ll.y, c*uv_ll.x - s*uv_ll.y)*uAspect.yx*vec2(0.85,1) + vec2(0.05,-0.06);

s = _qc.z;
c = _qc.w;
uv_rr = 0.5 + 1.8*vec2( s*uv_rr.x + c*uv_rr.y, c*uv_rr.x - s*uv_rr.y)*uAspect.yx*vec2(0.85,1) + vec2(-0.05,-0.06);

float1 l = texture(sampler_fc_main, uv_l).x;
float1 r = texture(sampler_fc_main, uv_r).x;
float1 ll = max(texture(sampler_fc_main, uv_ll).x,texture(sampler_fc_main, uv_ll).y);
float1 rr = max(texture(sampler_fc_main, uv_rr).x,texture(sampler_fc_main, uv_rr).z);
ret.x = max(limb,max(l,r));
ret.y = ll;
ret.z = rr;
ret = ret*1.2 - 0.01;

  fragColor = ret;
}

